const now = new Date().toISOString();
const gallicaOut = $('Collecte Gallica').item.json.stdout || '';
const gutenbergOut = $('Collecte Gutenberg').item.json.stdout || '';

return [{
  json: {
    timestamp: now,
    status: 'success',
    summary: `Pipeline LexicoTrend terminée le ${now}`,
    gallica_exit_code: gallicaOut.trim(),
    gutenberg_exit_code: gutenbergOut.trim()
  }
}];

// Log d'erreur Gallica
const stderr = $('Collecte Gallica').item.json.stderr || 'Erreur inconnue';
return [{ json: { error: 'Collecte Gallica échouée', detail: stderr.substring(0, 500) } }];

// Log d'erreur Gutenberg
const stderr = $('Collecte Gutenberg').item.json.stderr || 'Erreur inconnue';
return [{ json: { error: 'Collecte Gutenberg échouée', detail: stderr.substring(0, 500) } }];
